set -e; mkdir -p /etc/lightdm/lightdm.conf.d /etc/polkit-1/rules.d; printf 'policy:deny-removable-mount
' > /etc/lightdm/lightdm.conf.d/50-altcenter-deny-removable-mount.conf; printf 'polkit.addRule(function(action, subject) {
    if (action.id.indexOf("org.freedesktop.udisks2.filesystem-mount") == 0) {
        if (subject.user != "root") {
            return polkit.Result.NO;
        }
    }
});
' > /etc/polkit-1/rules.d/50-altcenter-deny-removable-mount.rules

